import{_ as i,c as e,o as n,ag as r,j as o,a as l,t as s}from"./chunks/framework.bCALENAD.js";const _=JSON.parse('{"title":"微信小程序","description":"","frontmatter":{},"headers":[],"relativePath":"notes/weixin/mini.md","filePath":"notes/weixin/mini.md","lastUpdated":1778069689000}'),a={name:"notes/weixin/mini.md"},d={class:"info custom-block"};function p(g,t,u,m,c,b){return n(),e("div",null,[t[6]||(t[6]=r('<h1 id="微信小程序" tabindex="-1">微信小程序 <a class="header-anchor" href="#微信小程序" aria-label="Permalink to &quot;微信小程序&quot;">​</a></h1><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><div class="info custom-block"><p class="custom-block-title">小程序特点</p><ul><li>类似于Web开发模式，入门的门槛低：基本上是类似于html+css+js；</li><li>可直接云端更新：微信审核，无需经过App Store等平台；</li><li>提升用户体验：通过提供基础能力、原生组件结合等方式，提升用户体验；</li><li>平台管控能力：小程序提供云端更新，通过代码上传、审核等方式，增强对开发者的管控能力；</li><li>双线程模型：逻辑层和渲染层分开加载，提供了管控型和安全性（沙盒环境运行JS代码，不允许执行任何和浏览器相关的接口，比如跳转页面、操作DOM等）；</li></ul></div><p><a href="https://developers.weixin.qq.com/miniprogram/dev/framework/release/" target="_blank" rel="noreferrer">微信小程序开发文档</a></p><p>小程序的开发主要分成三部分：</p><ul><li>页面布局：WXML，类似HTML</li><li>页面样式：WXSS，几乎就是CSS（某些不支持，某些进行了增强）</li><li>页面脚本：JavaScript+WXS，（JS，以及WeixinScript后续学习）</li></ul><h3 id="申请appid" tabindex="-1">申请APPID <a class="header-anchor" href="#申请appid" aria-label="Permalink to &quot;申请APPID&quot;">​</a></h3><ol><li><p><strong>访问微信公众平台</strong><br> 打开 <a href="https://mp.weixin.qq.com/" target="_blank" rel="noreferrer">微信公众平台</a>，使用微信扫描二维码登录</p></li><li><p><strong>选择小程序注册类型</strong><br> 点击&quot;立即注册&quot;，选择&quot;小程序&quot;类型</p></li><li><p><strong>填写注册信息</strong><br> 邮箱：一个未绑定微信公众平台的邮箱</p></li><li><p><strong>邮箱激活</strong><br> 登录注册邮箱，点击微信发送的激活链接</p></li><li><p><strong>信息登记</strong><br> 选择主体类型：个人/企业/政府、媒体、其他组织等</p></li><li><p><strong>完善小程序信息</strong><br> 小程序名称（需审核）/头像/简介</p></li><li><p><strong>获取 AppID</strong><br> 注册完成后，在&quot;开发&quot;-&quot;开发管理&quot;-&quot;开发设置&quot;中查看 AppID</p></li></ol><div class="info custom-block"><p class="custom-block-title">AppID的作用</p><ul><li><strong>开发调试</strong>：在微信开发者工具中配置 AppID 进行开发</li><li><strong>接口调用</strong>：调用微信 API 需要 AppID 验证身份</li><li><strong>发布上线</strong>：小程序上线审核需要已认证的 AppID</li></ul></div><div class="warning custom-block"><p class="custom-block-title">⚠️ 注意</p><ul><li>个人主体小程序功能有限，很多接口无法使用</li><li>企业主体小程序需要微信认证（300元/年）</li><li>小程序名称需符合微信命名规范，不能与已存在的小程序名称重复</li><li>AppID 泄露不会造成安全风险，但建议妥善保管</li></ul></div><p><a href="https://developers.weixin.qq.com/miniprogram/dev/devtools/download.html" target="_blank" rel="noreferrer">微信开发者工具</a></p><h2 id="小程序架构和配置" tabindex="-1">小程序架构和配置 <a class="header-anchor" href="#小程序架构和配置" aria-label="Permalink to &quot;小程序架构和配置&quot;">​</a></h2><h3 id="代码组织结构" tabindex="-1">代码组织结构 <a class="header-anchor" href="#代码组织结构" aria-label="Permalink to &quot;代码组织结构&quot;">​</a></h3><p>小程序代码组织结构分为三个级别：应用级别、页面级别和组件级别。</p><table tabindex="0"><thead><tr><th>级别</th><th>文件</th><th>说明</th></tr></thead><tbody><tr><td><strong>应用级别</strong></td><td>app.js</td><td>创建 App 实例的代码，包含全局逻辑和生命周期</td></tr><tr><td></td><td>app.json</td><td>全局配置，如 window、tabbar、页面路由等</td></tr><tr><td></td><td>app.wxss</td><td>全局样式，对所有页面生效</td></tr><tr><td><strong>页面级别</strong></td><td>page.js</td><td>创建 Page 实例的代码，包含页面逻辑和生命周期</td></tr><tr><td></td><td>page.json</td><td>页面单独配置，如 window 配置、usingComponents 等</td></tr><tr><td></td><td>page.wxml</td><td>页面的布局代码，类似于 HTML</td></tr><tr><td></td><td>page.wxss</td><td>页面样式，类似于 CSS</td></tr><tr><td><strong>组件级别</strong></td><td>component.js</td><td>创建 Component 实例的代码，包含组件逻辑</td></tr><tr><td></td><td>component.json</td><td>组件配置，声明依赖的其他组件</td></tr><tr><td></td><td>component.wxml</td><td>组件的布局代码</td></tr><tr><td></td><td>component.wxss</td><td>组件的样式代码</td></tr></tbody></table><h2 id="附录" tabindex="-1">附录 <a class="header-anchor" href="#附录" aria-label="Permalink to &quot;附录&quot;">​</a></h2><h3 id="附1-小程序mvvm架构" tabindex="-1">附1: 小程序MVVM架构 <a class="header-anchor" href="#附1-小程序mvvm架构" aria-label="Permalink to &quot;附1: 小程序MVVM架构&quot;">​</a></h3>',17)),o("div",d,[t[5]||(t[5]=o("p",{class:"custom-block-title"},"为什么像MVVM框架？（开发体验角度）",-1)),o("ul",null,[t[3]||(t[3]=o("li",null,[o("strong",null,"数据驱动视图"),l("：你只需要关注数据（"),o("code",null,"data"),l("）的变化，界面（WXML）会自动更新。")],-1)),o("li",null,[t[0]||(t[0]=o("strong",null,"双向绑定语法",-1)),t[1]||(t[1]=l("：小程序使用 ",-1)),o("code",null,s(),1),t[2]||(t[2]=l(" 进行数据绑定，这与 Vue.js 等框架的语法非常相似。",-1))]),t[4]||(t[4]=r("<li><strong>逻辑与视图分离</strong>： <ul><li><strong>View（视图层）</strong>：WXML 和 WXSS，负责展示。</li><li><strong>ViewModel（视图模型层）</strong>：框架底层帮你处理了数据绑定和事件监听。</li><li><strong>Model（模型层）</strong>：Page 或 Component 中的 <code>data</code> 和逻辑代码。</li></ul></li>",1))])]),t[7]||(t[7]=r('<div class="info custom-block"><p class="custom-block-title">为什么不是标准的MVVM框架？（底层实现角度）</p><ul><li><strong>双线程架构</strong>： <ul><li><strong>传统 MVVM（如 Vue/React 在浏览器中）</strong>：逻辑和视图运行在同一个线程（UI 线程），直接操作 DOM（或虚拟 DOM）。</li><li><strong>小程序</strong>：采用了<strong>逻辑层</strong>（JS）和<strong>视图层</strong>（WXML/WXSS）分开的<strong>双线程模型</strong>。 <ul><li><strong>逻辑层</strong>运行在 JS Core 中，没有浏览器对象（如 <code>window</code>、<code>document</code>），负责处理数据。</li><li><strong>视图层</strong>运行在 WebView 中，负责渲染界面。</li></ul></li><li><strong>通信机制</strong>：当数据变化时，逻辑层通过微信客户端（Native）作为桥梁，将数据序列化传输给视图层，视图层再重新渲染。这与 MVVM 框架中 JS 直接响应式更新 DOM 的机制不同。</li></ul></li></ul></div><h3 id="附2" tabindex="-1">附2: <a class="header-anchor" href="#附2" aria-label="Permalink to &quot;附2:&quot;">​</a></h3>',2))])}const q=i(a,[["render",p]]);export{_ as __pageData,q as default};
